/**
 * OrderTableRow - Table row component for displaying order in table view
 * Implements Requirement 10.8
 */

'use client'

import { useRouter } from 'next/navigation'
import { Order } from '@/src/types'
import { format } from 'date-fns'
import { useFilters, useSort, useLayout, usePagination } from '@/src/hooks/useUIStore'

interface OrderTableRowProps {
  order: Order
}

// Status badge colors per Requirement 4.7
const statusColors: Record<string, { bg: string; text: string; label: string }> = {
  submitted: { bg: 'bg-blue-100', text: 'text-blue-800', label: 'Shipment Created' },
  waiting: { bg: 'bg-orange-100', text: 'text-orange-800', label: 'Waiting for Pick Up' },
  closed: { bg: 'bg-green-100', text: 'text-green-800', label: 'Delivery Completed' },
  cancelled: { bg: 'bg-red-100', text: 'text-red-800', label: 'Shipment Cancelled' },
}

export function OrderTableRow({ order }: OrderTableRowProps) {
  const router = useRouter()
  const statusConfig = statusColors[order.status] || statusColors.submitted
  const { filters } = useFilters()
  const { sort } = useSort()
  const { layout } = useLayout()
  const { currentPage } = usePagination()

  const handleEdit = (e: React.MouseEvent) => {
    e.stopPropagation()
    router.push(`/create-order?edit=${order.id}`)
  }

  const handleCancel = async (e: React.MouseEvent) => {
    e.stopPropagation()
    if (confirm('Are you sure you want to cancel this order?')) {
      console.log('Cancel order:', order.id)
    }
  }

  const handleSeeDetail = (e: React.MouseEvent) => {
    e.stopPropagation()
    // Preserve filter and sort state in URL for back button (Requirement 10.12)
    const params = new URLSearchParams()
    params.set('page', String(currentPage))
    if (filters.dateRange.from) params.set('from', filters.dateRange.from.toISOString())
    if (filters.dateRange.to) params.set('to', filters.dateRange.to.toISOString())
    if (filters.statuses.length > 0) params.set('statuses', filters.statuses.join(','))
    if (filters.outletId) params.set('outletId', filters.outletId)
    if (filters.serviceTypes.length > 0) params.set('serviceTypes', filters.serviceTypes.join(','))
    if (filters.invoiceNumber) params.set('invoiceNumber', filters.invoiceNumber)
    params.set('sortField', sort.field)
    params.set('sortDir', sort.direction)
    params.set('layout', layout)

    router.push(`/orders/${order.id}?${params.toString()}`)
  }

  return (
    <tr
      className="border-b border-gray-100 hover:bg-gray-50 cursor-pointer transition-colors"
      onClick={handleSeeDetail}
    >
      {/* Order ID */}
      <td className="px-4 py-3">
        <span className="font-medium text-gray-900">{order.invoiceNumber}</span>
      </td>

      {/* Status */}
      <td className="px-4 py-3">
        <span className={`px-2 py-1 text-xs font-medium rounded-full ${statusConfig.bg} ${statusConfig.text}`}>
          {statusConfig.label}
        </span>
      </td>

      {/* Recipient */}
      <td className="px-4 py-3">
        <div>
          <p className="font-medium text-gray-900">{order.recipient.name}</p>
          <p className="text-sm text-gray-500 truncate max-w-[150px]">{order.recipient.address}</p>
        </div>
      </td>

      {/* Distance */}
      <td className="px-4 py-3">
        <span className="text-gray-700">{order.delivery.distance.toFixed(1)} km</span>
      </td>

      {/* Fee */}
      <td className="px-4 py-3">
        <span className="font-medium text-[#ED0577]">
          {new Intl.NumberFormat('id-ID', { style: 'currency', currency: 'IDR' }).format(order.delivery.shippingFee)}
        </span>
      </td>

      {/* Date */}
      <td className="px-4 py-3">
        <span className="text-gray-700">{format(new Date(order.createdAt), 'MMM d, yyyy')}</span>
      </td>

      {/* Actions */}
      <td className="px-4 py-3">
        <div className="flex items-center gap-1">
          <button
            onClick={handleEdit}
            className="p-1.5 text-gray-500 hover:text-[#ED0577] hover:bg-gray-100 rounded transition-colors min-w-[36px] min-h-[36px] flex items-center justify-center"
            aria-label="Edit order"
            disabled={order.status !== 'submitted'}
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
            </svg>
          </button>
          <button
            onClick={handleCancel}
            className="p-1.5 text-gray-500 hover:text-red-600 hover:bg-gray-100 rounded transition-colors min-w-[36px] min-h-[36px] flex items-center justify-center"
            aria-label="Cancel order"
            disabled={order.status !== 'submitted'}
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
          <button
            onClick={handleSeeDetail}
            className="p-1.5 text-gray-500 hover:text-[#ED0577] hover:bg-gray-100 rounded transition-colors min-w-[36px] min-h-[36px] flex items-center justify-center"
            aria-label="View order details"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
            </svg>
          </button>
        </div>
      </td>
    </tr>
  )
}

export default OrderTableRow