/**
 * OrderCard - Card component for displaying order in card view
 * Shows order ID, status badge, recipient name, distance, shipping fee
 * Action buttons (edit, cancel, see detail) appear on hover
 * Implements Requirement 10.9 and 10.11
 */

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { Order } from '@/src/types'
import { format } from 'date-fns'
import { useUpdateOrder } from '@/src/hooks/useUpdateOrder'
import { CancelOrderDialog } from '@/src/components/CancelOrderDialog'
import { useFilters, useSort, useLayout, usePagination } from '@/src/hooks/useUIStore'

interface OrderCardProps {
  order: Order
}

// Status badge colors per Requirement 4.7
const statusColors: Record<string, { bg: string; text: string; label: string }> = {
  submitted: { bg: 'bg-blue-100', text: 'text-blue-800', label: 'Shipment Created' },
  waiting: { bg: 'bg-orange-100', text: 'text-orange-800', label: 'Waiting for Pick Up' },
  closed: { bg: 'bg-green-100', text: 'text-green-800', label: 'Delivery Completed' },
  cancelled: { bg: 'bg-red-100', text: 'text-red-800', label: 'Shipment Cancelled' },
}

export function OrderCard({ order }: OrderCardProps) {
  const router = useRouter()
  const [showActions, setShowActions] = useState(false)
  const [showCancelDialog, setShowCancelDialog] = useState(false)
  const updateOrder = useUpdateOrder()
  const { filters } = useFilters()
  const { sort } = useSort()
  const { layout } = useLayout()
  const { currentPage } = usePagination()

  const statusConfig = statusColors[order.status] || statusColors.submitted

  // Only allow cancelling orders that are submitted or waiting (not already closed or cancelled)
  const canCancel = order.status === 'submitted' || order.status === 'waiting'

  const handleEdit = (e: React.MouseEvent) => {
    e.stopPropagation()
    router.push(`/create-order?edit=${order.id}`)
  }

  const handleCancel = async (e: React.MouseEvent) => {
    e.stopPropagation()
    setShowCancelDialog(true)
  }

  const handleCancelConfirm = async () => {
    try {
      await updateOrder.mutateAsync({
        id: order.id,
        updates: {
          status: 'cancelled',
          statusDisplay: 'Shipment Cancelled',
        },
      })
      setShowCancelDialog(false)
    } catch (error) {
      console.error('Failed to cancel order:', error)
    }
  }

  const handleSeeDetail = (e: React.MouseEvent) => {
    e.stopPropagation()
    // Preserve filter and sort state in URL for back button (Requirement 10.12)
    const params = new URLSearchParams()
    params.set('page', String(currentPage))
    if (filters.dateRange.from) params.set('from', filters.dateRange.from.toISOString())
    if (filters.dateRange.to) params.set('to', filters.dateRange.to.toISOString())
    if (filters.statuses.length > 0) params.set('statuses', filters.statuses.join(','))
    if (filters.outletId) params.set('outletId', filters.outletId)
    if (filters.serviceTypes.length > 0) params.set('serviceTypes', filters.serviceTypes.join(','))
    if (filters.invoiceNumber) params.set('invoiceNumber', filters.invoiceNumber)
    params.set('sortField', sort.field)
    params.set('sortDir', sort.direction)
    params.set('layout', layout)

    router.push(`/orders/${order.id}?${params.toString()}`)
  }

  return (
    <div
      className="relative bg-white border border-gray-200 rounded-lg p-4 hover:shadow-md transition-shadow cursor-pointer"
      onMouseEnter={() => setShowActions(true)}
      onMouseLeave={() => setShowActions(false)}
      onClick={handleSeeDetail}
    >
      {/* Header: Order ID and Status */}
      <div className="flex items-start justify-between mb-3">
        <div>
          <p className="text-sm text-gray-500">Order ID</p>
          <p className="font-semibold text-gray-900">{order.invoiceNumber}</p>
        </div>
        <span className={`px-2 py-1 text-xs font-medium rounded-full ${statusConfig.bg} ${statusConfig.text}`}>
          {statusConfig.label}
        </span>
      </div>

      {/* Recipient info */}
      <div className="mb-3">
        <p className="text-sm text-gray-500">Recipient</p>
        <p className="font-medium text-gray-900">{order.recipient.name}</p>
        <p className="text-sm text-gray-600 truncate">{order.recipient.address}</p>
      </div>

      {/* Details row */}
      <div className="grid grid-cols-2 gap-4 mb-3">
        <div>
          <p className="text-sm text-gray-500">Distance</p>
          <p className="font-medium text-gray-900">{order.delivery.distance.toFixed(1)} km</p>
        </div>
        <div>
          <p className="text-sm text-gray-500">Service</p>
          <p className="font-medium text-gray-900 capitalize">{order.delivery.serviceType}</p>
        </div>
      </div>

      {/* Fee and date */}
      <div className="flex items-center justify-between pt-3 border-t border-gray-100">
        <div>
          <p className="text-sm text-gray-500">Shipping Fee</p>
          <p className="font-semibold text-[#ED0577]">
            {new Intl.NumberFormat('id-ID', { style: 'currency', currency: 'IDR' }).format(order.delivery.shippingFee)}
          </p>
        </div>
        <div className="text-right">
          <p className="text-sm text-gray-500">Created</p>
          <p className="text-sm text-gray-700">{format(new Date(order.createdAt), 'MMM d, yyyy')}</p>
        </div>
      </div>

      {/* Action buttons - visible on hover */}
      <div
        className={`absolute inset-0 bg-white/95 rounded-lg flex items-center justify-center gap-2 transition-opacity ${
          showActions ? 'opacity-100' : 'opacity-0 pointer-events-none'
        }`}
      >
        <button
          onClick={handleEdit}
          className={`px-4 py-2 rounded-md transition-colors min-h-[44px] min-w-[80px] ${
            order.status === 'submitted'
              ? 'bg-[#ED0577] text-white hover:bg-[#d9066a]'
              : 'bg-gray-200 text-gray-400 cursor-not-allowed'
          }`}
          disabled={order.status !== 'submitted'}
          title={order.status !== 'submitted' ? 'Only pending orders can be edited' : ''}
        >
          Edit
        </button>
        <button
          onClick={handleCancel}
          className={`px-4 py-2 rounded-md transition-colors min-h-[44px] min-w-[80px] ${
            canCancel
              ? 'border border-gray-300 text-gray-700 hover:bg-gray-50'
              : 'border border-gray-200 text-gray-300 cursor-not-allowed'
          }`}
          disabled={!canCancel}
          title={!canCancel ? 'Only pending orders can be cancelled' : ''}
        >
          Cancel
        </button>
        <button
          onClick={handleSeeDetail}
          className="px-4 py-2 border border-gray-300 text-gray-700 rounded-md hover:bg-gray-50 transition-colors min-h-[44px] min-w-[80px]"
        >
          See Detail
        </button>
      </div>

      {/* Cancel Confirmation Dialog */}
      <CancelOrderDialog
        isOpen={showCancelDialog}
        invoiceNumber={order.invoiceNumber}
        recipientName={order.recipient.name}
        onConfirm={handleCancelConfirm}
        onCancel={() => setShowCancelDialog(false)}
      />
    </div>
  )
}

export default OrderCard