/**
 * OrderHistory - Paginated list of orders with filtering, layout toggle, and empty state
 * Implements Requirements 10.1, 10.8, 10.15
 */

'use client'

import { useMemo } from 'react'
import { useOrders } from '@/src/hooks/useOrders'
import { useFilters, useLayout, usePagination, useSort } from '@/src/hooks/useUIStore'
import { FilterBar } from '@/src/components/FilterBar'
import { LayoutToggle } from '@/src/components/LayoutToggle'
import { OrderCard } from '@/src/components/OrderCard'
import { OrderTableRow } from '@/src/components/OrderTableRow'
import { Pagination } from '@/src/components/Pagination'
import { EmptyState } from '@/src/components/EmptyState'
import { Order } from '@/src/types'

/**
 * Filter orders based on current filter state
 */
function filterOrders(orders: Order[], filters: ReturnType<typeof useFilters>['filters']): Order[] {
  return orders.filter((order) => {
    // Date range filter
    if (filters.dateRange.from) {
      const orderDate = new Date(order.createdAt)
      if (orderDate < filters.dateRange.from) return false
    }
    if (filters.dateRange.to) {
      const orderDate = new Date(order.createdAt)
      const endOfDay = new Date(filters.dateRange.to)
      endOfDay.setHours(23, 59, 59, 999)
      if (orderDate > endOfDay) return false
    }

    // Status filter
    if (filters.statuses.length > 0 && !filters.statuses.includes(order.status)) {
      return false
    }

    // Outlet filter
    if (filters.outletId && order.outletId !== filters.outletId) {
      return false
    }

    // Service type filter
    if (filters.serviceTypes.length > 0 && !filters.serviceTypes.includes(order.delivery.serviceType)) {
      return false
    }

    // Invoice number filter
    if (filters.invoiceNumber) {
      const searchTerm = filters.invoiceNumber.toLowerCase()
      if (!order.invoiceNumber.toLowerCase().includes(searchTerm)) {
        return false
      }
    }

    return true
  })
}

/**
 * Sort orders based on current sort state
 */
function sortOrders(orders: Order[], sort: { field: 'date' | 'status'; direction: 'asc' | 'desc' }): Order[] {
  return [...orders].sort((a, b) => {
    if (sort.field === 'date') {
      const dateA = new Date(a.createdAt).getTime()
      const dateB = new Date(b.createdAt).getTime()
      return sort.direction === 'asc' ? dateA - dateB : dateB - dateA
    } else {
      // Sort by status - group by status then by date
      const statusOrder = { submitted: 0, waiting: 1, closed: 2, cancelled: 3 }
      const statusCompare = statusOrder[a.status] - statusOrder[b.status]
      if (statusCompare !== 0) {
        return sort.direction === 'asc' ? statusCompare : -statusCompare
      }
      // Same status, sort by date
      const dateA = new Date(a.createdAt).getTime()
      const dateB = new Date(b.createdAt).getTime()
      return sort.direction === 'asc' ? dateA - dateB : dateB - dateA
    }
  })
}

export function OrderHistory() {
  const { data: orders = [], isLoading, error } = useOrders()
  const { filters } = useFilters()
  const { layout } = useLayout()
  const { currentPage, itemsPerPage, setCurrentPage } = usePagination()
  const { sort, setSort, toggleSortDirection } = useSort()

  // Filter and sort orders
  const filteredOrders = useMemo(() => filterOrders(orders, filters), [orders, filters])
  const sortedOrders = useMemo(() => sortOrders(filteredOrders, sort), [filteredOrders, sort])

  // Paginate orders
  const totalPages = Math.ceil(sortedOrders.length / itemsPerPage)
  const paginatedOrders = useMemo(() => {
    const start = (currentPage - 1) * itemsPerPage
    return sortedOrders.slice(start, start + itemsPerPage)
  }, [sortedOrders, currentPage, itemsPerPage])

  // Reset to page 1 when filters change
  const handleFilterChange = () => {
    setCurrentPage(1)
  }

  // Handle sort click
  const handleSortClick = (field: 'date' | 'status') => {
    if (sort.field === field) {
      toggleSortDirection()
    } else {
      setSort({ field, direction: 'desc' })
    }
  }

  // Calculate showing range
  const showingStart = sortedOrders.length === 0 ? 0 : (currentPage - 1) * itemsPerPage + 1
  const showingEnd = Math.min(currentPage * itemsPerPage, sortedOrders.length)

  if (error) {
    return (
      <div className="p-6">
        <div className="bg-red-50 border border-red-200 rounded-lg p-4">
          <p className="text-red-600">Error loading orders. Please try again.</p>
        </div>
      </div>
    )
  }

  return (
    <div className="p-4 md:p-6 lg:p-8">
      {/* Page header */}
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900">Order History</h1>
        <p className="text-gray-600 mt-1">
          {sortedOrders.length} {sortedOrders.length === 1 ? 'order' : 'orders'} total
        </p>
      </div>

      {/* Filter bar */}
      <FilterBar onFilterChange={handleFilterChange} />

      {/* Layout toggle and sort controls */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-6">
        <LayoutToggle />

        {/* Sort controls */}
        <div className="flex items-center gap-2">
          <span className="text-sm text-gray-600">Sort by:</span>
          <button
            onClick={() => handleSortClick('date')}
            className={`px-3 py-1.5 text-sm rounded-md transition-colors min-h-[36px] ${
              sort.field === 'date'
                ? 'bg-[#ED0577] text-white'
                : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
            }`}
          >
            Date {sort.field === 'date' && (sort.direction === 'asc' ? '↑' : '↓')}
          </button>
          <button
            onClick={() => handleSortClick('status')}
            className={`px-3 py-1.5 text-sm rounded-md transition-colors min-h-[36px] ${
              sort.field === 'status'
                ? 'bg-[#ED0577] text-white'
                : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
            }`}
          >
            Status {sort.field === 'status' && (sort.direction === 'asc' ? '↑' : '↓')}
          </button>
        </div>
      </div>

      {/* Orders list */}
      {isLoading ? (
        <div className="flex items-center justify-center py-12">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-[#ED0577]"></div>
        </div>
      ) : sortedOrders.length === 0 ? (
        <EmptyState
          title="No orders found"
          description="Try adjusting your filters or create a new order."
        />
      ) : (
        <>
          {/* Card view */}
          {layout === 'card' && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {paginatedOrders.map((order) => (
                <OrderCard key={order.id} order={order} />
              ))}
            </div>
          )}

          {/* Table view */}
          {layout === 'table' && (
            <div className="overflow-x-auto">
              <table className="w-full border-collapse">
                <thead>
                  <tr className="bg-gray-50 border-b border-gray-200">
                    <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">
                      Order ID
                    </th>
                    <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">
                      Status
                    </th>
                    <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">
                      Recipient
                    </th>
                    <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">
                      Distance
                    </th>
                    <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">
                      Fee
                    </th>
                    <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">
                      Date
                    </th>
                    <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">
                      Actions
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {paginatedOrders.map((order) => (
                    <OrderTableRow key={order.id} order={order} />
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {/* Pagination */}
          {totalPages > 1 && (
            <Pagination
              currentPage={currentPage}
              totalPages={totalPages}
              totalItems={sortedOrders.length}
              showingStart={showingStart}
              showingEnd={showingEnd}
              onPageChange={setCurrentPage}
            />
          )}
        </>
      )}
    </div>
  )
}

export default OrderHistory