/**
 * FilterBar - Filter controls for order history
 * Includes: date range, status, outlet, service type, invoice number
 */

'use client'

import { useState } from 'react'
import { useFilters } from '@/src/hooks/useUIStore'
import { useOutlets } from '@/src/hooks/useOutlets'
import { OrderStatus, ServiceType } from '@/src/types'

interface FilterBarProps {
  onFilterChange?: () => void
}

const statusOptions: { value: OrderStatus; label: string }[] = [
  { value: 'submitted', label: 'Shipment Created' },
  { value: 'waiting', label: 'Waiting for Pick Up' },
  { value: 'closed', label: 'Delivery Completed' },
  { value: 'cancelled', label: 'Shipment Cancelled' },
]

const serviceTypeOptions: { value: ServiceType; label: string }[] = [
  { value: 'standard', label: 'Standard' },
  { value: 'express', label: 'Express' },
  { value: 'same-day', label: 'Same-Day' },
]

export function FilterBar({ onFilterChange }: FilterBarProps) {
  const { filters, setDateRange, setStatuses, setOutletId, setServiceTypes, setInvoiceNumber, resetFilters } = useFilters()
  const { data: outlets = [] } = useOutlets()
  
  const [isExpanded, setIsExpanded] = useState(false)

  const handleFilterUpdate = () => {
    onFilterChange?.()
  }

  const handleReset = () => {
    resetFilters()
    onFilterChange?.()
  }

  const hasActiveFilters = 
    filters.dateRange.from !== null ||
    filters.dateRange.to !== null ||
    filters.statuses.length > 0 ||
    filters.outletId !== null ||
    filters.serviceTypes.length > 0 ||
    filters.invoiceNumber !== ''

  return (
    <div className="bg-white border border-gray-200 rounded-lg mb-6">
      {/* Toggle button for mobile */}
      <button
        onClick={() => setIsExpanded(!isExpanded)}
        className="w-full md:hidden flex items-center justify-between px-4 py-3 text-left min-h-[44px]"
      >
        <span className="font-medium text-gray-700">
          {isExpanded ? 'Hide Filters' : 'Show Filters'}
          {hasActiveFilters && <span className="ml-2 text-[#ED0577]">(Active)</span>}
        </span>
        <svg
          className={`w-5 h-5 transition-transform ${isExpanded ? 'rotate-180' : ''}`}
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
        >
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
        </svg>
      </button>

      {/* Filter content */}
      <div className={`${isExpanded || 'hidden md:block'} p-4 space-y-4`}>
        {/* Invoice number search */}
        <div>
          <label htmlFor="invoice-search" className="block text-sm font-medium text-gray-700 mb-1">
            Invoice Number
          </label>
          <input
            type="text"
            id="invoice-search"
            placeholder="Search invoice number..."
            value={filters.invoiceNumber}
            onChange={(e) => {
              setInvoiceNumber(e.target.value)
              handleFilterUpdate()
            }}
            className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-[#ED0577] focus:border-transparent min-h-[44px]"
          />
        </div>

        {/* Date range */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label htmlFor="date-from" className="block text-sm font-medium text-gray-700 mb-1">
              From Date
            </label>
            <input
              type="date"
              id="date-from"
              value={filters.dateRange.from ? new Date(filters.dateRange.from).toISOString().split('T')[0] : ''}
              onChange={(e) => {
                setDateRange(e.target.value ? new Date(e.target.value) : null, filters.dateRange.to)
                handleFilterUpdate()
              }}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-[#ED0577] focus:border-transparent min-h-[44px]"
            />
          </div>
          <div>
            <label htmlFor="date-to" className="block text-sm font-medium text-gray-700 mb-1">
              To Date
            </label>
            <input
              type="date"
              id="date-to"
              value={filters.dateRange.to ? new Date(filters.dateRange.to).toISOString().split('T')[0] : ''}
              onChange={(e) => {
                setDateRange(filters.dateRange.from, e.target.value ? new Date(e.target.value) : null)
                handleFilterUpdate()
              }}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-[#ED0577] focus:border-transparent min-h-[44px]"
            />
          </div>
        </div>

        {/* Status filter */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Status
          </label>
          <div className="flex flex-wrap gap-2">
            {statusOptions.map((status) => (
              <button
                key={status.value}
                onClick={() => {
                  const newStatuses = filters.statuses.includes(status.value)
                    ? filters.statuses.filter((s) => s !== status.value)
                    : [...filters.statuses, status.value]
                  setStatuses(newStatuses)
                  handleFilterUpdate()
                }}
                className={`px-3 py-1.5 text-sm rounded-full transition-colors min-h-[36px] ${
                  filters.statuses.includes(status.value)
                    ? 'bg-[#ED0577] text-white'
                    : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                }`}
              >
                {status.label}
              </button>
            ))}
          </div>
        </div>

        {/* Service type filter */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Service Type
          </label>
          <div className="flex flex-wrap gap-2">
            {serviceTypeOptions.map((service) => (
              <button
                key={service.value}
                onClick={() => {
                  const newTypes = filters.serviceTypes.includes(service.value)
                    ? filters.serviceTypes.filter((t) => t !== service.value)
                    : [...filters.serviceTypes, service.value]
                  setServiceTypes(newTypes)
                  handleFilterUpdate()
                }}
                className={`px-3 py-1.5 text-sm rounded-full transition-colors min-h-[36px] ${
                  filters.serviceTypes.includes(service.value)
                    ? 'bg-[#ED0577] text-white'
                    : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                }`}
              >
                {service.label}
              </button>
            ))}
          </div>
        </div>

        {/* Outlet filter */}
        <div>
          <label htmlFor="outlet-filter" className="block text-sm font-medium text-gray-700 mb-1">
            Outlet
          </label>
          <select
            id="outlet-filter"
            value={filters.outletId || ''}
            onChange={(e) => {
              setOutletId(e.target.value || null)
              handleFilterUpdate()
            }}
            className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-[#ED0577] focus:border-transparent min-h-[44px]"
          >
            <option value="">All Outlets</option>
            {outlets.map((outlet) => (
              <option key={outlet.id} value={outlet.id}>
                {outlet.name}
              </option>
            ))}
          </select>
        </div>

        {/* Reset button */}
        {hasActiveFilters && (
          <button
            onClick={handleReset}
            className="px-4 py-2 text-sm text-gray-600 hover:text-[#ED0577] transition-colors min-h-[44px] flex items-center"
          >
            <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
            Clear Filters
          </button>
        )}
      </div>
    </div>
  )
}

export default FilterBar